#include <stdio.h>
#include <stdlib.h>
int compare(const void *a, const void *b) { return (*(int*)a - *(int*)b); }
int main() {
    int n;
    scanf("%d", &n);
    int chocolates[n];
    for (int i = 0; i < n; i++) {
        scanf("%d", &chocolates[i]);
    }
    qsort(chocolates, n, sizeof(int), compare);
    int median = chocolates[n / 2];
    int operations = 0;
    for (int i = 0; i < n; i++) {
        operations += abs(chocolates[i] - median);
    }
    printf("%d\n", operations);
    return 0;
}

