code.Java:
import java.util.Arrays;
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int n = scanner.nextInt();
        int[] chocolates = new int[n];
        for (int i = 0; i < n; i++) {
            chocolates[i] = scanner.nextInt();
        }
        Arrays.sort(chocolates);
        int median = chocolates[n / 2];
        int operations = 0;
        for (int i = 0; i < n; i++) {
            operations += Math.abs(chocolates[i] - median);
        }
        System.out.println(operations);
    }
}

code.JavaScript:
const readline = require('readline');
const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});
let n;
let chocolates;
rl.on('line', (input) => {
    if (!n) {
        n = parseInt(input);
    } else {
        chocolates = input.split(' ').map(Number);
        chocolates.sort((a, b) => a - b);
        const median = chocolates[Math.floor(n / 2)];
        let operations = 0;
        for (let i = 0; i < n; i++) {
            operations += Math.abs(chocolates[i] - median);
        }
        console.log(operations);
        rl.close();
    }
});

